import{_ as l,o as t,c as i,ae as a}from"./chunks/framework.CyZiF_rV.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ru/tryby-offline.md","filePath":"ru/tryby-offline.md"}'),o={name:"ru/tryby-offline.md"};function r(n,e,f,d,h,s){return t(),i("div",null,[...e[0]||(e[0]=[a('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/tryby-offline.md" target="_blank" rel="noreferrer">tryby-offline.md</a></p></blockquote><h2 id="автономные-режимы" tabindex="-1">Автономные режимы <a class="header-anchor" href="#автономные-режимы" aria-label="Permalink to &quot;Автономные режимы&quot;">​</a></h2><p>10.07.2025</p><h2 id="введение" tabindex="-1">Введение <a class="header-anchor" href="#введение" aria-label="Permalink to &quot;Введение&quot;">​</a></h2><p>В системе KSeF доступны два основных режима выставления счетов-фактур:</p><ul><li>режим <code>online</code> - счет-фактура выставляется и передается в режиме реального времени в систему KSeF,</li><li>режим <code>offline</code> - счет-фактура выставляется и передается в KSeF в более поздний, установленный законом срок.</li></ul><p>В автономном режиме счета-фактуры выставляются электронно, в соответствии с действующим образцом структуры FA(3). Наиболее важные технические аспекты:</p><ul><li>При отправке счета-фактуры – как в интерактивном, так и в пакетном режиме – необходимо установить параметр <code>offlineMode: true</code>.</li><li>В случае счетов-фактур, передаваемых как online (offlineMode: false), система KSeF может самостоятельно присвоить им автономный режим - на основании сравнения даты выставления с датой принятия. Подробности механизма: <a href="./offline/automatyczne-okreslanie-trybu-offline.html">Автоматическое определение режима отправки offline</a>.</li><li>За дату выставления система KSeF принимает исключительно значение, содержащееся в поле <code>P_1</code> структуры электронного счета-фактуры.</li><li>Дата получения счета-фактуры - это дата присвоения номера KSeF или в случае предоставления вне KSeF, дата фактического ее получения.</li><li>После выставления счета-фактуры в автономном режиме клиентское приложение должно сгенерировать два <a href="./kody-qr.html">QR-кода</a> для визуализации счета-фактуры: <ul><li><strong>КОД I</strong> – позволяет верифицировать счет-фактуру в системе KSeF,</li><li><strong>КОД II</strong> – подтверждает идентичность выставителя.</li></ul></li><li>Корректирующий счет-фактуру передают только после присвоения номера KSeF первичному документу.</li><li>В случае если переданный автономный счет-фактура будет отклонен по техническим причинам, возможно использование механизма <a href="/ksef-docs/offline/korekta-techniczna.html">технической коррекции</a>.</li></ul><h3 id="сводка-режимов-выставления-счетов-фактур-в-ksef-–-offline24-offline-и-аварииныи" tabindex="-1">Сводка режимов выставления счетов-фактур в KSeF – offline24, offline и аварийный <a class="header-anchor" href="#сводка-режимов-выставления-счетов-фактур-в-ksef-–-offline24-offline-и-аварииныи" aria-label="Permalink to &quot;Сводка режимов выставления счетов-фактур в KSeF – offline24, offline и аварийный&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Режим</th><th>Сторона ответственности</th><th>Обстоятельства запуска</th><th>Срок передачи в KSeF</th><th>Правовая основа</th></tr></thead><tbody><tr><td><strong>offline24</strong></td><td>клиент</td><td>Без ограничений (по усмотрению налогоплательщика)</td><td>до следующего рабочего дня после даты выставления</td><td>ст. 106nda закона о НДС (проект KSeF 2.0)</td></tr><tr><td><strong>offline</strong></td><td>система KSeF</td><td>Недоступность системы (объявлена в BIP и в интерфейсном программном обеспечении)</td><td>до следующего рабочего дня после окончания недоступности</td><td>ст. 106nh закона о НДС (с 1 II 2026)</td></tr><tr><td><strong>аварийный</strong></td><td>система KSeF</td><td>Авария KSeF (сообщение в BIP MF и в интерфейсном программном обеспечении)</td><td>до 7 раб. дней от окончания аварии (при следующем сообщении счетчик считается заново)</td><td>ст. 106nf закона о НДС (с 1 II 2026)</td></tr></tbody></table><h3 id="срок-передачи-счета-фактуры-в-ksef-при-последующих-событиях" tabindex="-1">Срок передачи счета-фактуры в KSeF при последующих событиях <a class="header-anchor" href="#срок-передачи-счета-фактуры-в-ksef-при-последующих-событиях" aria-label="Permalink to &quot;Срок передачи счета-фактуры в KSeF при последующих событиях&quot;">​</a></h3><p>В режимах offline24 и offline, если в ожидаемый период досылки счета-фактуры будет объявлена авария KSeF (сообщение в BIP MF или в интерфейсном программном обеспечении), срок передачи сдвигается и исчисляется с дня окончания последней объявленной аварии, не более 7 рабочих дней.</p><p>В аварийном режиме, если в течение семидневного периода для досылки счета-фактуры появится следующее сообщение об аварии, счетчик срока сбрасывается и исчисляется с дня окончания этой следующей аварии.</p><p>Объявление полной аварии в течение любого из вышеуказанных режимов приводит к снятию обязанности передачи счетов-фактур в KSeF.</p><h4 id="пример-режим-offline24-с-объявленнои-авариеи-ksef" tabindex="-1">Пример: режим offline24 с объявленной аварией KSeF <a class="header-anchor" href="#пример-режим-offline24-с-объявленнои-авариеи-ksef" aria-label="Permalink to &quot;Пример: режим offline24 с объявленной аварией KSeF&quot;">​</a></h4><ol><li>2025-07-08 (среда) <ul><li>Налогоплательщик генерирует счет-фактуру в режиме offline24 (offlineMode = true).</li><li>Срок передачи в KSeF устанавливается на 2025-07-09 (следующий рабочий день).</li></ul></li><li>2025-07-09 (четверг) <ul><li>Министерство финансов публикует сообщение об аварии KSeF (BIP и интерфейс API).</li><li>Согласно правилу: первоначальный срок сдвигается, а новый исчисляется с дня окончания аварии.</li></ul></li><li>2025-07-12 (суббота) <ul><li>Авария устраняется – система снова доступна.</li><li>Начинается период 7 рабочих дней для досылки просроченного счета-фактуры.</li></ul></li><li>2025-07-22 (вторник) <ul><li>Истекает срок 7 рабочих дней с окончания аварии.</li><li>Приложение до этой даты имеет время для отправки счета-фактуры в KSeF с установленным offlineMode = true.</li></ul></li></ol><h3 id="режим-полнои-аварии" tabindex="-1">Режим полной аварии <a class="header-anchor" href="#режим-полнои-аварии" aria-label="Permalink to &quot;Режим полной аварии&quot;">​</a></h3><p>В случае объявления полной аварии (средства массовой информации: ТВ, радио, пресса, Интернет):</p><ul><li>Счет-фактуру можно выставить в бумажной или электронной форме, без обязанности применения образца FA(3).</li><li>Нет обязанности передачи счета-фактуры в KSeF после прекращения аварии.</li><li>Передача покупателю происходит любым каналом (лично, e-mail, другие).</li><li>Датой выставления всегда является фактическая дата, указанная на счете-фактуре, а датой получения - дата фактического получения счета-фактуры покупки.</li><li>Счета-фактуры из этого режима не снабжаются QR-кодами.</li><li>Корректирующий счет-фактура во время продолжающейся аварии KSeF выставляется аналогично – вне KSeF, с фактической датой.</li></ul><h2 id="связанные-документы" tabindex="-1">Связанные документы <a class="header-anchor" href="#связанные-документы" aria-label="Permalink to &quot;Связанные документы&quot;">​</a></h2><ul><li><a href="./offline/korekta-techniczna.html">Техническая коррекция автономного счета-фактуры</a></li><li><a href="./kody-qr.html">QR-коды</a></li></ul>',21)])])}const F=l(o,[["render",r]]);export{c as __pageData,F as default};
